import{_ as o,c as a,o as r,a2 as t}from"./chunks/framework.aRVg8jgk.js";const u=JSON.parse('{"title":"Glossary","description":"Definitions for Lynq-specific terms: CRDs, labels, annotations, policy types, template functions, and core Kubernetes concepts used throughout the docs.","frontmatter":{"description":"Definitions for Lynq-specific terms: CRDs, labels, annotations, policy types, template functions, and core Kubernetes concepts used throughout the docs."},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md","lastUpdated":1779353865000}'),n={name:"glossary.md"};function s(c,e,i,d,l,h){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><p>Quick-reference definitions. For deeper explanations, follow the linked pages.</p><h2 id="index" tabindex="-1">Index <a class="header-anchor" href="#index" aria-label="Permalink to &quot;Index&quot;">​</a></h2><p><a href="#a">A</a> · <a href="#c">C</a> · <a href="#d">D</a> · <a href="#e">E</a> · <a href="#f">F</a> · <a href="#h">H</a> · <a href="#l">L</a> · <a href="#m">M</a> · <a href="#n">N</a> · <a href="#o">O</a> · <a href="#p">P</a> · <a href="#r">R</a> · <a href="#s">S</a> · <a href="#t">T</a> · <a href="#v">V</a> · <a href="#w">W</a></p><hr><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><p><strong>activate</strong> — The database column mapped to control whether a row provisions resources. Accepted truthy values: <code>1</code>, <code>true</code>, <code>TRUE</code>, <code>True</code>, <code>yes</code>, <code>YES</code>, <code>Yes</code>. Everything else (including <code>NULL</code>) is inactive. → <a href="./datasource.html">Datasource</a></p><p><strong>appliedResources</strong> — A <code>status</code> field on LynqNode listing every resource currently managed, in <code>kind/namespace/name@id</code> format. Used for orphan detection: resources in <code>appliedResources</code> but not in the current template become orphans.</p><hr><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><p><strong>cascade deletion</strong> — Automatic deletion of child resources when a parent is deleted. Deleting a LynqHub removes all its LynqNode CRs; each LynqNode&#39;s finalizer then cleans up managed resources per their <code>deletionPolicy</code>. → <a href="./policies-operations.html">Policy Operations</a></p><p><strong>cert-manager</strong> — Required Kubernetes add-on (v1.13.0+) that provisions TLS certificates for Lynq&#39;s admission webhooks. → <a href="./installation.html">Installation</a></p><p><strong>ConflictPolicy</strong> — Per-resource policy controlling behavior when SSA detects a field owner conflict. <code>Stuck</code> (default) stops reconciliation and marks the node Degraded; <code>Force</code> takes ownership with <code>force=true</code>. → <a href="./policies.html">Policies</a></p><p><strong>CreationPolicy</strong> — Per-resource policy controlling update behavior. <code>WhenNeeded</code> (default) re-applies only when the rendered spec changes (and during periodic drift-correction); <code>Once</code> creates the resource once and never updates it again. → <a href="./policies.html">Policies</a></p><p><strong>CRD (Custom Resource Definition)</strong> — Kubernetes extension that adds new resource types. Lynq installs three: <code>lynqhubs.operator.lynq.sh</code>, <code>lynqforms.operator.lynq.sh</code>, <code>lynqnodes.operator.lynq.sh</code>.</p><hr><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><p><strong>DAG (Directed Acyclic Graph)</strong> — The dependency graph built from each resource&#39;s <code>dependIds</code>. Cycles are rejected at admission time. Lynq performs a topological sort to determine apply order.</p><p><strong>dependIds</strong> — Array field on <code>TResource</code>. Lists IDs of resources that must be applied (and ready, if <code>waitForReady: true</code>) before this resource is processed. → <a href="./dependencies.html">Dependencies</a></p><p><strong>DeletionPolicy</strong> — Per-resource policy controlling lifecycle on LynqNode deletion. <code>Delete</code> (default) uses <code>ownerReference</code> for automatic GC; <code>Retain</code> uses label-based tracking and leaves the resource in the cluster. Evaluated at creation time — not deletion time. → <a href="./policies.html">Policies</a></p><p><strong>drift detection</strong> — The process of detecting and correcting manual changes to managed resources. Lynq uses event-driven watches (immediate) plus a 30-second periodic requeue for eventual consistency.</p><hr><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><p><strong>extraValueMappings</strong> — Optional LynqHub field for mapping additional database columns to template variables. <code>extraValueMappings: planId: subscription_plan</code> makes <code>.planId</code> available in all templates. → <a href="./datasource.html">Datasource</a></p><hr><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><p><strong>fieldManager</strong> — SSA identifier marking which controller owns which fields. Lynq uses <code>lynq-operator</code> as its field manager. Other controllers retain ownership of their own fields.</p><p><strong>finalizer</strong> — Kubernetes mechanism preventing resource deletion until cleanup completes. Lynq adds <code>lynqnode.operator.lynq.sh/finalizer</code> to every LynqNode CR to ensure managed resources are cleaned up before the CR is removed.</p><p><strong>Form Builder</strong> — A GUI tool in the Lynq dashboard for building LynqForm specs visually. → <a href="./template-builder.html">Form Builder</a></p><hr><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><p><strong>hub</strong> — Short for LynqHub. See <a href="#lynqhub">LynqHub</a>.</p><hr><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><p><strong>Infrastructure as Data (IaD)</strong> — The paradigm where database rows are the source of truth for infrastructure state. INSERT/UPDATE/DELETE rows → Kubernetes resources appear/change/disappear. → <a href="./introduction.html">Introduction</a></p><hr><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><p><strong>LynqForm</strong> — CRD defining the Kubernetes resource blueprint for one set of active rows. Each form references a LynqHub and defines which resources (Deployments, Services, etc.) to create per active row, using Go templates. → <a href="./api-lynqform.html">API Reference</a></p><p><strong>LynqHub</strong> — CRD defining the database connection (MySQL), sync interval, and column mappings. The hub queries the database and creates/deletes LynqNode CRs to match the active row set. → <a href="./api-lynqhub.html">API Reference</a></p><p><strong>LynqNode</strong> — CRD representing one active row × one LynqForm combination. Created automatically by the LynqHub controller. Tracks the status of all managed resources and drives reconciliation. → <a href="./api-lynqnode.html">API Reference</a></p><p><strong><code>lynq.sh/node</code></strong> — Label on cross-namespace resources and namespace resources. Value is the LynqNode CR name. Used for tracking when <code>ownerReference</code> can&#39;t be used.</p><p><strong><code>lynq.sh/node-namespace</code></strong> — Label on cross-namespace resources. Value is the LynqNode namespace.</p><p><strong><code>lynq.sh/orphaned</code></strong> — Label set to <code>&quot;true&quot;</code> on retained resources after the LynqNode is deleted or the resource is removed from the template. Find orphans: <code>kubectl get all -A -l lynq.sh/orphaned=true</code>.</p><hr><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><p><strong>multi-form</strong> — Configuration where one LynqHub is referenced by multiple LynqForms. Each active row × each form = one LynqNode. A hub with 5 active rows and 3 forms creates 15 LynqNodes.</p><hr><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><p><strong>nameTemplate</strong> — Go template string that generates <code>metadata.name</code> for a resource. Must produce a valid Kubernetes name (lowercase, alphanumeric, <code>-</code>) up to 63 characters. Use <code>trunc63</code> to enforce the limit.</p><hr><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><p><strong>orphan</strong> — A resource previously managed by Lynq that is no longer in the template (or whose LynqNode was deleted). Resources with <code>DeletionPolicy: Retain</code> become orphans rather than being deleted.</p><p><strong>orphan markers</strong> — Labels and annotations added to retained resources:</p><ul><li><code>lynq.sh/orphaned: &quot;true&quot;</code></li><li><code>lynq.sh/orphaned-at: (RFC3339 timestamp)</code></li><li><code>lynq.sh/orphaned-reason: &quot;RemovedFromTemplate&quot;</code> or <code>&quot;LynqNodeDeleted&quot;</code></li></ul><p><strong>ownerReference</strong> — Kubernetes metadata establishing a parent-child GC relationship. Resources with <code>DeletionPolicy: Delete</code> have an <code>ownerReference</code> pointing to their LynqNode. Resources with <code>DeletionPolicy: Retain</code> do not.</p><hr><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><p><strong>PatchStrategy</strong> — Per-resource policy controlling how updates are applied. <code>apply</code> (default, SSA), <code>merge</code> (strategic merge patch), <code>replace</code> (full replacement). → <a href="./policies.html">Policies</a></p><hr><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><p><strong>RecordOps</strong> — Lynq&#39;s term for the practice of using database record operations (INSERT/UPDATE/DELETE) as the primary mechanism for infrastructure change. See <a href="#i">Infrastructure as Data</a>.</p><p><strong>reconciliation</strong> — The control loop where the operator compares desired state (templates + DB rows) with actual cluster state and applies changes to converge them. Triggered by DB sync, CRD changes, child resource changes, and a 30-second periodic requeue.</p><hr><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><p><strong>Server-Side Apply (SSA)</strong> — Kubernetes API mechanism for declarative, field-manager-aware updates. Lynq uses SSA as the default apply method. Each controller owns only the fields it sets; other controllers own their fields independently.</p><p><strong>skipOnDependencyFailure</strong> — Boolean field on <code>TResource</code> (default: <code>true</code>). When <code>true</code>, a resource is skipped if any of its dependencies failed. When <code>false</code>, it&#39;s applied regardless.</p><p><strong>syncInterval</strong> — LynqHub field setting the database poll frequency. Format: Go duration (<code>30s</code>, <code>1m</code>, <code>5m</code>). Default: <code>30s</code>. → <a href="./datasource.html">Datasource</a></p><hr><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><div><p><strong><code>toHost</code></strong> — Custom template function. <code>{{ .nodeUrl | toHost }}</code> extracts the hostname from a URL string.</p></div><p><strong>topological sort</strong> — Algorithm used to determine apply order from the dependency graph. Resources with no dependencies are applied first; dependents follow.</p><p><strong>TResource</strong> — The base structure for every resource entry in a LynqForm. Holds <code>id</code>, <code>spec</code>, <code>nameTemplate</code>, <code>dependIds</code>, the four policies, and readiness settings. → <a href="./api-lynqform.html">API Reference</a></p><p><strong><code>trunc63</code></strong> — Custom template function. Truncates a string to 63 characters (the Kubernetes name length limit). Use in <code>nameTemplate</code> when UIDs may be long.</p><hr><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><p><strong>valueMappings</strong> — Required LynqHub field mapping database column names to the two required template variables: <code>uid</code> and <code>activate</code>. → <a href="./datasource.html">Datasource</a></p><hr><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><p><strong>waitForReady</strong> — Boolean field on <code>TResource</code> (default: <code>true</code>). When <code>true</code>, Lynq waits for the resource&#39;s ready condition before applying dependent resources. → <a href="./dependencies.html">Dependencies</a></p><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./introduction.html">Introduction</a> — what Lynq is and when to use it</li><li><a href="./architecture.html">Architecture</a> — three-controller design</li><li><a href="./policies.html">Policies</a> — CreationPolicy, DeletionPolicy, ConflictPolicy, PatchStrategy</li><li><a href="./templates.html">Templates</a> — template syntax and available functions</li></ul>',82)])])}const f=o(n,[["render",s]]);export{u as __pageData,f as default};
